Use ASP.NET Core's **`WebApplicationFactory<T>`** — it hosts your app in-memory with no real network port.

### Setup

```bash
dotnet add package Microsoft.AspNetCore.Mvc.Testing
```

### Example test

```csharp
using Microsoft.AspNetCore.Mvc.Testing;
using System.Net.Http.Json;
using System.Text.Json;

public class McpIntegrationTests
    : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsServerCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2.0", body.GetProperty("jsonrpc").GetString());
        Assert.True(body.TryGetProperty("result", out var result));
        Assert.True(result.TryGetProperty("serverInfo", out _));
    }

    [Fact]
    public async Task ToolsCall_ExecutesTool()
    {
        // Initialize first (stateful session)
        await InitializeSession();

        var request = new
        {
            jsonrpc = "2.0",
            id = 2,
            method = "tools/call",
            @params = new
            {
                name = "my-tool",
                arguments = new { input = "hello" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var content = body.GetProperty("result")
                         .GetProperty("content")[0];
        Assert.Equal("text", content.GetProperty("type").GetString());
    }

    private async Task InitializeSession() { /* same as above */ }
}
```

### Key points

| Concern | Approach |
|---|---|
| **No real port** | `WebApplicationFactory` uses an in-memory `TestServer` |
| **Session state** | Reuse the same `HttpClient` — cookies/headers persist |
| **MCP-Session-Id** | Capture it from `initialize` response headers and send on subsequent requests |
| **SSE streaming** | Read via `response.Content.ReadAsStreamAsync()` + `StreamReader`, parse `data:` lines |
| **DI overrides** | Use `factory.WithWebHostBuilder(b => b.ConfigureServices(...))` to swap dependencies |

Make sure your `Program` class is accessible to the test project (add `InternalsVisibleTo` or use a `public partial class Program { }` marker in your server's `Program.cs`).
